  LESSON_QUESTIONS['AI Tools']['Prompt Basics'].push(
    { type: 'multiple_choice', prompt: 'What is a "prompt" in the context of AI language models?', options: ['A type of programming language', 'An error message from the AI', 'A software update notification', 'The text input you provide to an AI to generate a response'], correctAnswer: 'The text input you provide to an AI to generate a response', difficulty: 'easy', explanation: 'A prompt is the instruction, question, or context you give to an AI model. The quality and specificity of the prompt directly affects the output quality.' },
    { type: 'multiple_choice', prompt: 'Which element most improves the quality of an AI prompt?', options: ['Including emojis', 'Using all capital letters', 'Making it as short as possible', 'Adding specific context, format requirements, and constraints'], correctAnswer: 'Adding specific context, format requirements, and constraints', difficulty: 'medium', explanation: 'Specific prompts get specific results. Including context (who, what, why), desired format (list, paragraph, code), and constraints (word count, tone) dramatically improves output.' },
    { type: 'multiple_choice', prompt: 'What is "prompt engineering"?', options: ['The practice of designing and refining inputs to get optimal AI outputs', 'Building hardware for AI', 'Debugging AI code', 'A type of software engineering'], correctAnswer: 'The practice of designing and refining inputs to get optimal AI outputs', difficulty: 'easy', explanation: 'Prompt engineering is the skill of crafting effective prompts. It involves understanding how AI interprets instructions and iterating to improve results.' },
    { type: 'true_false', prompt: 'A vague prompt like "write something good" will typically produce a useful, targeted response.', options: ['True', 'False'], correctAnswer: 'False', difficulty: 'easy', explanation: 'Vague prompts produce vague outputs. AI models need clear direction about topic, audience, format, tone, and length to produce useful content.' },
    { type: 'true_false', prompt: 'Providing examples in your prompt can help the AI understand the desired output format and style.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'medium', explanation: 'Including examples (few-shot prompting) shows the AI exactly what you want, reducing ambiguity and improving consistency of outputs.' },
    { type: 'fill_gap', prompt: 'The technique of providing example inputs and outputs within a prompt is called ___-shot prompting.', options: ['few', 'one', 'multi', 'zero'], correctAnswer: 'few', difficulty: 'hard', explanation: 'Few-shot prompting provides 2-5 examples in the prompt. Zero-shot provides none. Few-shot generally produces more accurate, consistent results.' }
  );

  LESSON_QUESTIONS['AI Tools']['Prompt Structure'].push(
    { type: 'multiple_choice', prompt: 'What are the key components of a well-structured AI prompt?', options: ['Just the question', 'A greeting and farewell', 'Only the desired word count', 'Role, context, task, format, and constraints'], correctAnswer: 'Role, context, task, format, and constraints', difficulty: 'medium', explanation: 'A structured prompt includes: who the AI should act as (role), background info (context), what to do (task), how to present it (format), and limits (constraints).' },
    { type: 'multiple_choice', prompt: 'What is a "system prompt" or "role" in prompt structure?', options: ['The AI\'s error log', 'The user\'s username', 'An instruction that sets the AI\'s persona, expertise, and behavioral guidelines', 'A login password'], correctAnswer: 'An instruction that sets the AI\'s persona, expertise, and behavioral guidelines', difficulty: 'easy', explanation: 'System prompts like "You are an expert copywriter" shape the AI\'s responses by establishing expertise, tone, and behavioral boundaries.' },
    { type: 'multiple_choice', prompt: 'Why is specifying output format important in a prompt?', options: ['It ensures the AI returns information in a usable structure like bullet points, tables, or JSON', 'It reduces the cost of API calls', 'It makes the AI faster', 'It is not important'], correctAnswer: 'It ensures the AI returns information in a usable structure like bullet points, tables, or JSON', difficulty: 'medium', explanation: 'Without format instructions, AI may return a wall of text. Specifying "return as a numbered list" or "format as a table" saves you time reformatting.' },
    { type: 'true_false', prompt: 'Adding "Think step by step" to a prompt can improve the AI\'s reasoning on complex problems.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'Step-by-step instructions activate chain-of-thought reasoning, helping the AI break down complex problems and produce more logical, thorough answers.' },
    { type: 'true_false', prompt: 'The order of instructions in a prompt does not matter — AI processes all parts equally.', options: ['True', 'False'], correctAnswer: 'False', difficulty: 'hard', explanation: 'AI models pay more attention to the beginning and end of prompts. Placing critical instructions at the start or end can improve adherence.' },
    { type: 'fill_gap', prompt: 'Setting the AI\'s persona with an instruction like "You are a senior data analyst" is called ___ prompting.', options: ['role', 'task', 'format', 'chain'], correctAnswer: 'role', difficulty: 'easy', explanation: 'Role prompting assigns the AI a specific identity, shaping its vocabulary, expertise level, and communication style for more relevant outputs.' }
  );

  LESSON_QUESTIONS['AI Tools']['Chain of Thought'].push(
    { type: 'multiple_choice', prompt: 'What is chain-of-thought prompting?', options: ['Linking multiple AI tools together', 'Asking the AI to show its reasoning step by step before giving a final answer', 'A type of blockchain technology', 'Sending multiple prompts in a row'], correctAnswer: 'Asking the AI to show its reasoning step by step before giving a final answer', difficulty: 'easy', explanation: 'Chain-of-thought prompting improves AI reasoning by making the model explicitly work through each logical step rather than jumping to conclusions.' },
    { type: 'multiple_choice', prompt: 'For which type of task is chain-of-thought prompting most beneficial?', options: ['Complex reasoning, math, and multi-step logic problems', 'Translating single words', 'Generating short creative text', 'Simple factual lookups'], correctAnswer: 'Complex reasoning, math, and multi-step logic problems', difficulty: 'medium', explanation: 'Chain-of-thought shines on tasks requiring logic: math problems, code debugging, strategic analysis, and any multi-step reasoning challenge.' },
    { type: 'multiple_choice', prompt: 'What phrase is commonly used to activate chain-of-thought reasoning?', options: ['"Keep it short"', '"Let\'s think step by step"', '"Be creative"', '"Answer quickly"'], correctAnswer: '"Let\'s think step by step"', difficulty: 'easy', explanation: 'The phrase "Let\'s think step by step" has been shown in research to significantly improve AI performance on reasoning tasks.' },
    { type: 'true_false', prompt: 'Chain-of-thought prompting can reduce errors in mathematical reasoning by AI models.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'medium', explanation: 'When AI models show their work step by step, they are more likely to catch intermediate errors and arrive at correct final answers.' },
    { type: 'true_false', prompt: 'Chain-of-thought is equally useful for simple yes/no questions as it is for complex analysis.', options: ['True', 'False'], correctAnswer: 'False', difficulty: 'hard', explanation: 'Simple factual questions do not benefit from chain-of-thought. The technique adds value mainly for multi-step reasoning, analysis, and complex problem-solving.' },
    { type: 'fill_gap', prompt: 'Breaking a complex problem into smaller logical ___ before solving is the core idea behind chain-of-thought prompting.', options: ['steps', 'files', 'prompts', 'models'], correctAnswer: 'steps', difficulty: 'easy', explanation: 'Decomposing problems into steps forces the AI to reason through each part, producing more accurate and transparent results.' }
  );

